/* OpenMgmtMapper.getOpenMgmtListNew */
SELECT REQ.RES_NO AS resNo /*예약번호 */ , SUB.SCAN_ID AS scanId /*스캔ID */ , REQ.REQUEST_KEY AS requestKey , REQ.PROD_TYPE_NM AS prodTypeNm /*상품구분 */ , SUB.CONTRACT_NUM AS contractNum /*계약번호 */ , SUB.SUB_LINK_NAME AS cstmrName /*고객명 */ , SUB.USER_SSN AS ssn /*주민번호 */ , SUB.SUBSCRIBER_NO AS subscriberNo /*휴대폰번호 */ , REQ.LST_RATE_NM AS lstRateNm /*현재요금제 */ , CASE WHEN SUBSTR(REQ.SIM_INFO, 36, 1) IN ('A', 'R') THEN ( SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(REQ.SIM_INFO, 1, 2)) ELSE (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0058' AND CD_VAL = SUBSTR(REQ.INST_INFO, 1, 2)) END AS sprtTpNm /*할인유형 */ , REQ.SALE_PLCY_NM AS salePlcyNm /*판매정책 */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 26, 3)) AS enggMnthCnt /*약정개월수 */ , TO_NUMBER(SUBSTR(REQ.INST_INFO, 23, 3)) AS instMnthCnt /*할부개월수 */ , SUB.MODEL_NAME AS lstModelNm /*단말모델명 */ , SUB.INTM_SRL_NO AS lstModelSrlNum /*단말일련번호 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'MSP0003' AND CD_VAL = SUB.SUB_STATUS) AS subStatusNm /*상태 */ , CASE WHEN SUB.SUB_STATUS = 'C' THEN CASE WHEN TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') = 0 THEN '당일개통취소'
WHEN TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 THEN '14일이내해지' WHEN TO_DATE(SUBSTR(SUB.SUB_STATUS_DATE, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 90 THEN '90일이내해지'
ELSE '일반해지' END ELSE '' END AS canRsn /*해지사유 */ , REQ.ON_OFF_TYPE AS onOffType /* 모집경로 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'RCP0007' AND CD_VAL = REQ.ON_OFF_TYPE) AS onOffTypeNm , REQ.OPEN_MARKET_REFERER AS openMarketReferer /*유입경로 */ , REQ.RECOMMEND_FLAG_NM AS recommendFlagNm /*추천인구분 */ , REQ.RECOMMEND_INFO AS recommendInfo /*추천인정보 */ , REQ.REC_YN AS recYn /*녹취여부 */ , FN_GET_ORGNM(SUB.OPEN_AGNT_CD) || '/' || SUB.OPEN_AGNT_CD AS agentNm /*대리점 */ , REQ.SHOP_NM AS shopNm /*판매점 */ , DECODE(REQ.SHOP_USM_ID, NULL, '-' , REQ.SHOP_USM_ID) AS shopUsrId /*판매자ID */ , DECODE(REQ.SHOP_USM_ID, NULL, '-' , (SELECT A.USR_NM FROM CMN_USR_MST A WHERE A.USR_ID = REQ.SHOP_USM_ID)) AS shopUsrNm /*판매자명 */ , REQ.REQ_PAY_TYPE AS reqPayType /*요금납부방법 */ , REQ.REQUEST_STATE_CODE AS requestStateCode /*개통진행상태 */ , REQ.CSTMR_TYPE AS cstmrType /*고객구분코드 */ , SUB.SUB_LINK_NAME AS custNmVoc /*고객명VOC용 */ , SUB.SUBSCRIBER_NO AS ctnVoc /*휴대폰번호VOC용 */ , SUBSTR(REQ.DVC_CHG_INFO, 1, 8) AS dvcChgDt /* 기변일자 */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 9, 10)) AS dvcModelId /* 기변모델ID */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 19, 30)) AS dvcModelNm /* 기변모델명 */ , TRIM(SUBSTR(REQ.DVC_CHG_INFO, 49, 20)) AS dvcIntmSrlNo /* 기변일련번호 */ , FN_GET_ORGNM(TRIM(SUBSTR(REQ.DVC_CHG_INFO, 69, 10))) AS dvcAgntNm /* 기변대리점 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0049' AND CD_VAL = SUBSTR(REQ.DVC_CHG_INFO, 79, 4)) AS dvcOperTypeNm /* 기변유형명 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 83, 10)) AS dvcHndstAmnt /* 기변단말출고가 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 93, 10)) AS dvcInstOrginAmnt /* 기변단말할부원금 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 103, 3)) AS dvcInstMnthCnt /* 기변단말할부개월수 */ , TO_NUMBER(SUBSTR(REQ.DVC_CHG_INFO, 106, 3)) AS dvcEnggMnthCnt /* 기변약정개월수 */ , SUBSTR(REQ.DVC_CHG_INFO, 109) AS dvcSalePlcyNm /* 기변판매정책 */ , SUB.TRNS_YN AS trnsYn /* 이관여부 */ , (SELECT PROMOTION_NM FROM MSP_PROMOTION_MST WHERE PROMOTION_CD = REQ.PROMOTION_CD) AS promotionNm /* 프로모션명 */ , CASE SUBSTR(REQ.DIS_PRMT_ID, 1, 1) WHEN 'F' THEN (SELECT '(오프라인) ' || PRMT_NM FROM MSP_DIS_MST WHERE PRMT_ID = REQ.DIS_PRMT_ID) WHEN 'C' THEN (SELECT '(온라인) ' || PRMT_NM FROM MSP_CHRG_PRMT WHERE PRMT_ID = REQ.DIS_PRMT_ID) ELSE '' END AS disPrmtNm /* 평생할인 프로모션명*/ ,SUB.BAN AS ban /* 청구번호*/ ,SUB.IMEI AS imei FROM MSP_JUO_SUB_INFO SUB , MSP_REQUEST_DTL REQ
, ( SELECT CONTRACT_NUM FROM MSP_JUO_MODEL_INFO WHERE INTM_SRL_NO = #{searchName} GROUP BY CONTRACT_NUM ) MDL
, MSP_PARTNER_USIM_MST PUM
WHERE SUB.PPPO = 'PO' AND SUB.CONTRACT_NUM = REQ.CONTRACT_NUM
AND SUB.LST_COM_ACTV_DATE BETWEEN #{lstComActvDateF} AND #{lstComActvDateT}
AND SUB.SUB_STATUS = #{subStatus}
AND (SUB.OPEN_AGNT_CD = #{cntpntShopId} OR TRIM(SUBSTR(REQ.DVC_CHG_INFO, 69, 10)) = #{cntpntShopId})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQ_BUY_TYPE = #{reqBuyTypeS}
AND REQ.ON_OFF_TYPE = #{onOffType}
AND REQ.CSTMR_TYPE = 'NM'
AND REQ.APP_BLCK_AGRM_YN = 'Y'
AND REQ.APP_INST_YN = 'Y'
AND SUB.SUB_LINK_NAME LIKE #{searchName} || '%'
AND (SUB.CONTRACT_NUM = #{searchName} OR SUB.CONTRACT_NUM = (SELECT DISTINCT CONTRACT_NUM FROM MSP_JUO_SUB_INFO_HIST WHERE SVC_CNTR_NO = #{searchName}))
AND SUB.SUBSCRIBER_NO = #{searchName}
AND SUB.CONTRACT_NUM = MDL.CONTRACT_NUM
AND REQ.REQUEST_KEY IS NULL
AND EXISTS ( SELECT 1 FROM LGS_TELECOM_IF WHERE SVC_CT_NUM = SUB.CONTRACT_NUM AND LGS_PRCS_YN = 'Y' AND PRDT_TYPE_CD = 'D1' AND TO_DATE(SUBSTR(SVC_OPEN_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUB.LST_COM_ACTV_DATE, 'YYYYMMDD') < 15 ) AND EXISTS ( SELECT 1 FROM MSP_JUO_MODEL_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND MODEL_TYPE = 'D1' AND EVNT_CD = 'C07' )
AND REQ.LST_RATE_NM LIKE '%' || #{searchName} || '%'
AND EXISTS ( SELECT 1 FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND SIM_ID IS NOT NULL )
AND EXISTS ( SELECT 1 FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = SUB.CONTRACT_NUM AND BL_DC_TYPE = #{sprtTp} )
AND NVL(REQ.PROD_TYPE, '01') = #{prodType}
AND ( REQ.OPER_TYPE = #{operType} OR EXISTS ( SELECT 1 FROM MSP_DVC_CHG_AGNT_HST X, MSP_REQUEST Y WHERE X.REQUEST_KEY = Y.REQUEST_KEY AND X.CONTRACT_NUM = SUB.CONTRACT_NUM AND TO_DATE(SUBSTR(APPL_END_DTTM, 1, 8), 'YYYYMMDD') - TO_DATE(SUBSTR(APPL_STRT_DTTM, 1, 8), 'YYYYMMDD') > 14 AND Y.OPER_TYPE = #{operType}
AND SUBSTR(X.APPL_STRT_DTTM, 1, 8) BETWEEN #{lstComActvDateF} AND #{lstComActvDateT}
) )
AND SUB.USIM_TYPE = 'E'
AND REQ.FST_USIM_NO = PUM.USIM_NO(+) AND PUM.ORGN_ID = #{usimOrgCd}
AND SUBSTR(CRYPTO_AES256.DEC_AES(SUB.USER_SSN), 0, 6) = #{pBirthDayVal}
ORDER BY SUB.LST_COM_ACTV_DATE DESC

mapper.update:
/* OpenMgmtMapper.updateAppInstYnCnfm */
UPDATE	MSP_REQUEST_AGENT
SET		APP_INST_YN			= #{appInstYn}
		, INST_CNFM_ID		= #{instCnfmId}
		, INST_CNFM_DTTM	= SYSDATE
WHERE	REQUEST_KEY	= #{requestKey}

mapper.select:
/* OpenMgmtMapper.getApplFormInfo */ SELECT A.REQUEST_KEY AS requestKey , A.CSTMR_TYPE AS cstmrType /*고객구분*/ , A.SERVICE_TYPE AS serviceType /*서비스구분*/ , (SELECT CODE_NAME FROM MCP_CODE@DL_MCP WHERE CODE_SYS = 'PRO' AND CODE = A.SERVICE_TYPE) AS serviceName , A.OPER_TYPE AS operType /*업무구분*/ , (SELECT CODE_NAME FROM MCP_CODE@DL_MCP WHERE CODE_SYS = 'BSN' AND CODE = A.OPER_TYPE) AS operName , TO_CHAR(A.REQ_IN_DAY, 'YYYY-MM-DD') AS reqInDay /*신청일자*/ , A.ONLINE_AUTH_INFO AS onlineAuthInfo /*본인인증정보*/ , A.ONLINE_AUTH_TYPE AS onlineAuthType /*본인인증방식*/ , A.PSTATE AS pstate /*신청취소*/ , A.REQUEST_STATE_CODE AS requestStateCode /*개통진행상태*/ , (SELECT CODE_NAME FROM MCP_CODE@DL_MCP WHERE CODE_SYS = 'OPP' AND CODE = A.REQUEST_STATE_CODE) , A.ON_OFF_TYPE AS onOffType /*모집경로*/ , A.RES_NO AS resNo /*예약번호*/ , A.SCAN_ID AS scanId /*스캔아이디*/ , A.MANAGER_CODE AS managerCode /*매니저코드*/ , A.REQ_BUY_TYPE AS reqBuyType /*구매유형*/ , A.REQ_MODEL_NAME AS reqModelName /*휴대폰모델명*/ , A.REQ_MODEL_COLOR AS reqModelColor /*휴대폰색상*/ , A.REQ_WANT_NUMBER AS reqWantNumber /*가입희망번호*/ , A.REQ_WANT_NUMBER2 AS reqWantNumber2 /*가입희망번호2*/ , A.REQ_WANT_NUMBER3 AS reqWantNumber3 /*가입희망번호3*/ , A.REQ_USIM_SN AS reqUsimSn /*유심번호*/ , A.REQ_PHONE_SN AS reqPhoneSn /*단말기일련번호*/ , A.SPC_CODE AS spcCode /*특별판매코드*/ , A.MEMO AS requestMemo /*메모*/ , DECODE(A.CLAUSE_PRI_COLLECT_FLAG, 'Y', 1, 0) AS clausePriCollectFlag /* 약관_개인정보_수집_동의 */ , DECODE(A.CLAUSE_PRI_OFFER_FLAG, 'Y', 1, 0) AS clausePriOfferFlag /* 약관_개인정보_제공_동의 */ , DECODE(A.CLAUSE_ESS_COLLECT_FLAG, 'Y', 1, 0) AS clauseEssCollectFlag /* 약관_고유식별정보_수집이용제공_동의 */ , DECODE(A.CLAUSE_PRI_TRUST_FLAG, 'Y', 1, 0) AS clausePriTrustFlag /* 약관_개인정보_위탁_동의 */ , DECODE(A.CLAUSE_PRI_AD_FLAG, 'Y', 1, 0) AS clausePriAdFlag /* 약관_개인정보_광고전송_동의 */ , DECODE(A.CLAUSE_CONFIDENCE_FLAG, 'Y', 1, 0) AS clauseConfidenceFlag /* 약관_신용정보_이용_동의 */ , B.SOC_CODE AS socCode /*요금제*/
, (SELECT RATE_NM FROM MSP_RATE_MST MRM WHERE MRM.RATE_CD = B.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1) || NVL2(B.SOC_CODE, ' (' || B.SOC_CODE || ')', '') AS socName , '가입비 : ' || B.JOIN_PRICE || ' / 유심비 : ' || B.USIM_PRICE || (CASE WHEN A.OPER_TYPE = 'MNP3' THEN ' / ' || ' 번호이동 시 수수료 800원' END ) AS trmnlInfo /*단말정보*/ , C.CSTMR_NAME AS cstmrName /*고객명*/ , NVL(TRIM(C.CSTMR_NATIVE_RRN), TRIM(C.CSTMR_FOREIGNER_PN)) AS ssn /*생년월일(내국인주민번호앞6자리 또는 여권번호)*/ , TRIM(C.CSTMR_FOREIGNER_PN) AS cstmrForeignerPn /*여권번호*/ , C.CSTMR_FOREIGNER_SDATE AS cstmrForeignerSdate /*체류기간1*/ , C.CSTMR_FOREIGNER_EDATE AS cstmrForeignerEdate /*체류기간2*/ , C.CSTMR_JURIDICAL_CNAME AS cstmrJuridicalCname /*법인명*/ , C.CSTMR_JURIDICAL_RRN AS cstmrJuridicalRrn , SUBSTR(C.CSTMR_JURIDICAL_RRN, 1, 6) AS cstmrJuridicalRrn1 /*법인번호1*/ , SUBSTR(C.CSTMR_JURIDICAL_RRN, 7, 7) AS cstmrJuridicalRrn2 /*법인번호2*/ , C.CSTMR_JURIDICAL_NUMBER , SUBSTR(C.CSTMR_JURIDICAL_NUMBER, 1, 3) AS cstmrJuridicalNumber1 /*사업자번호1(법인)*/ , SUBSTR(C.CSTMR_JURIDICAL_NUMBER, 4, 2) AS cstmrJuridicalNumber2 /*사업자번호2(법인)*/ , SUBSTR(C.CSTMR_JURIDICAL_NUMBER, 6, 5) AS cstmrJuridicalNumber3 /*사업자번호3(법인)*/ , C.CSTMR_PRIVATE_CNAME AS cstmrPrivateCname /*상호명*/ , C.CSTMR_PRIVATE_NUMBER AS cstmrPrivateNumber , SUBSTR(C.CSTMR_PRIVATE_NUMBER, 1, 3) AS cstmrPrivateNumber1 /*사업자번호1(개인)*/ , SUBSTR(C.CSTMR_PRIVATE_NUMBER, 4, 2) AS cstmrPrivateNumber2 /*사업자번호2(개인)*/ , SUBSTR(C.CSTMR_PRIVATE_NUMBER, 6, 5) AS cstmrPrivateNumber3 /*사업자번호3(개인)*/ , C.CSTMR_MAIL , SUBSTR(C.CSTMR_MAIL, 1, INSTR(C.CSTMR_MAIL, '@') - 1) AS cstmrMail1 /*메일주소1*/ , SUBSTR(C.CSTMR_MAIL, INSTR(C.CSTMR_MAIL, '@') + 1) AS cstmrMail2 /*메일주소2*/ , C.CSTMR_MAIL_RECEIVE_FLAG AS cstmrMailReceiveFlag /*메일수신여부*/ , C.CSTMR_POST AS cstmrPost /*우편번호*/ , C.CSTMR_ADDR AS cstmrAddr /*고객주소*/ , C.CSTMR_ADDR_DTL AS cstmrAddrDtl /*상세주소*/ , C.CSTMR_BILL_SEND_CODE AS cstmrBillSendCode /*명세서수신유형*/ , C.CSTMR_TEL_FN || '-' || C.CSTMR_TEL_MN || '-' || C.CSTMR_TEL_RN AS cstmrTel , C.CSTMR_TEL_FN AS cstmrTelFn /*전화번호1*/ , C.CSTMR_TEL_MN AS cstmrTelMn /*전화번호2*/ , C.CSTMR_TEL_RN AS cstmrTelRn /*전화번호3*/ , C.CSTMR_MOBILE_FN || '-' || C.CSTMR_MOBILE_MN || '-' || C.CSTMR_MOBILE_RN AS cstmrMobile , C.CSTMR_MOBILE_FN AS cstmrMobileFn /*휴대폰번호1*/ , C.CSTMR_MOBILE_MN AS cstmrMobileMn /*휴대폰번호2*/ , C.CSTMR_MOBILE_RN AS cstmrMobileRn /*휴대폰번호3*/ , D.DLVRY_NAME AS dlvryName /*배송정보_받으시는분*/ , D.DLVRY_TEL_FN || '-' || D.DLVRY_TEL_MN || '-' || D.DLVRY_TEL_RN AS dlvryTel , D.DLVRY_TEL_FN AS dlvryTelFn /*배송정보_전화번호1*/ , D.DLVRY_TEL_MN AS dlvryTelMn /*배송정보_전화번호2*/ , D.DLVRY_TEL_RN AS dlvryTelRn /*배송정보_전화번호3*/ , D.DLVRY_MOBILE_FN || '-' || D.DLVRY_MOBILE_MN || '-' || D.DLVRY_MOBILE_RN AS dlvryMobile , D.DLVRY_MOBILE_FN AS dlvryMobileFn /*배송정보_휴대폰1*/ , D.DLVRY_MOBILE_MN AS dlvryMobileMn /*배송정보_휴대폰2*/ , D.DLVRY_MOBILE_RN AS dlvryMobileRn /*배송정보_휴대폰3*/ , D.DLVRY_POST AS dlvryPost /*배송정보_우편번호*/ , D.DLVRY_ADDR AS dlvryAddr /*배송정보_주소*/ , D.DLVRY_ADDR_DTL AS dlvryAddrDtl /*배송정보_상세주소*/ , D.DLVRY_MEMO AS dlvryMemo /*배송정보_메모*/ , E.TB_CD AS tbCd /*택배사*/ , E.DLVRY_NO AS dlvryNo /*송장번호*/ , A.REQ_PAY_TYPE AS reqPayType /*요금납부방법*/ , F.REQ_PAY_OTHER_FLAG AS othersPaymentAg /*타인납부여부*/ , NVL(CASE WHEN A.REQ_PAY_TYPE = 'C' THEN TRANSLATE(C.OTHERS_PAYMENT_AG,'YN','10') END, 0) AS othersPaymentAgClone /*타인납부여부(카드)*/ , F.REQ_BANK AS reqBank /*납부정보_은행*/ , F.REQ_ACCOUNT_NUMBER AS reqAccountNumber /*납부정보_계좌번호*/ , F.REQ_ACCOUNT_NAME AS reqAccountName /*납부정보_예금주명 */ , TRIM(F.REQ_ACCOUNT_RRN) AS reqAccountRrn /*납부정보_예금주주민번호*/ , F.REQ_ACCOUNT_RELATION AS reqAccountRelation , F.REQ_CARD_NAME AS reqCardName /*납부정보_카드_명의자*/ , TRIM(F.REQ_CARD_RRN) AS reqCardRrn /*납부정보_카드주_주민번호*/ , F.REQ_CARD_COMPANY AS reqCardCompany /*납부정보_카드사*/ , F.REQ_CARD_NO AS reqCardNo /*납부정보_카드번호*/ , F.REQ_CARD_MM AS reqCardMm /*납부정보_유효기간_월*/ , F.REQ_CARD_YY AS reqCardYy /*납부정보_유효기간_년*/ , (CASE WHEN INSTR(F.REQ_WIRE_TYPE,'AY') > 0 THEN 1 ELSE 0 END) AS reqWireType1 /*신청정보_무선데이터_이용_타입(이용)*/ , (CASE WHEN INSTR(F.REQ_WIRE_TYPE,'AN') > 0 THEN 1 ELSE 0 END) AS reqWireType2 /*신청정보_무선데이터_이용_타입(차단)*/ , (CASE WHEN INSTR(F.REQ_WIRE_TYPE,'DN') > 0 THEN 1 ELSE 0 END) AS reqWireType3 /*신청정보_무선데이터_이용_타입(데이터로밍차단)*/ , G.MINOR_AGENT_NAME AS minorAgentName /*미성년자_법정대리인_성명*/ , G.MINOR_AGENT_RELATION AS minorAgentRelation /*미성년자_법정대리인_관계*/ , TRIM(G.MINOR_AGENT_RRN) AS minorAgentRrn /*미성년자_법정대리인_주민번호*/ , G.MINOR_AGENT_TEL_FN || '-' || G.MINOR_AGENT_TEL_MN || '-' || G.MINOR_AGENT_TEL_RN AS minorAgentTel , G.MINOR_AGENT_TEL_FN AS minorAgentTelFn /*미성년자_법정대리인_연락처1*/ , G.MINOR_AGENT_TEL_MN AS minorAgentTelMn /*미성년자_법정대리인_연락처2*/ , G.MINOR_AGENT_TEL_RN AS minorAgentTelRn /*미성년자_법정대리인_연락처3*/ , TRANSLATE(H.REQ_GUIDE_FLAG, 'YN', '10') AS reqGuideFlag /*신청정보_번호연결서비스_여부*/ , H.REQ_GUIDE_FN || '-' || H.REQ_GUIDE_MN || '-' || H.REQ_GUIDE_RN AS reqGuide , H.REQ_GUIDE_FN AS reqGuideFn /*신청정보_번호연결_전화번호1*/ , H.REQ_GUIDE_MN AS reqGuideMn /*신청정보_번호연결_전화번호2*/ , H.REQ_GUIDE_RN AS reqGuideRn /*신청정보_번호연결_전화번호3*/ , H.MOVE_COMPANY AS moveCompany /*번호이동_변경전통신사*/ , H.MOVE_MOBILE_FN || '-' || H.MOVE_MOBILE_MN || '-' || H.MOVE_MOBILE_RN AS moveMobile , H.MOVE_MOBILE_FN AS moveMobileFn /*번호이동_이동번호1*/ , H.MOVE_MOBILE_MN AS moveMobileMn /*번호이동_이동번호2*/ , H.MOVE_MOBILE_RN AS moveMobileRn /*번호이동_이동번호3*/ , H.MOVE_THISMONTH_PAY_TYPE AS moveThismonthPayType /*번호이동_이달사용요금납부방법*/ , H.MOVE_ALLOTMENT_STAT AS moveAllotmentStat /*번호이동_휴대폰_할부금상태*/ , H.MOVE_REFUND_AGREE_FLAG AS moveRefundAgreeFlag /*번호이동_미환급액요금상계동의_여부*/ , H.MOVE_AUTH_TYPE AS moveAuthType /*번호이동_인증유형*/ , H.MOVE_AUTH_NUMBER AS moveAuthNumber /*번호이동_인증번호*/ , I.REQ_AC_TYPE AS reqAcType /*충전방법*/ , I.REQ_AC01_BALANCE AS reqAc01Balance /*충전잔액*/ , I.REQ_AC02_DAY AS reqAc02Day /*충전일*/ , DECODE(I.REQ_AC_TYPE, '01', I.REQ_AC01_AMOUNT, I.REQ_AC02_AMOUNT) AS reqAcAmount /*충전금액*/ , ( SELECT LISTAGG(ADDITION_NAME, ',') WITHIN GROUP(ORDER BY ADDITION_NAME) ADDITION_NAME FROM MCP_REQUEST_ADDITION@DL_MCP WHERE REQUEST_KEY = A.REQUEST_KEY GROUP BY REQUEST_KEY ) AS additionName /*부가서비스명*/ , DECODE(A.NW_BLCK_AGRM_YN, 'Y', 1, 0) AS nwBlckAgrmYn /*네트워크_차단동의*/ , DECODE(A.APP_BLCK_AGRM_YN, 'Y', 1, 0) AS appBlckAgrmYn /*유해정보차단APP_설치동의*/ , ( SELECT CODE_NAME FROM MCP_CODE@DL_MCP WHERE CODE_SYS = 'CHA' AND CODE = A.APP_CD) AS appNm /*유해정보차단APP명*/
, B.MODEL_SALE_POLICY_CODE AS plcyCd /*판매정책코드*/ , (SELECT SALE_PLCY_NM FROM MSP_SALE_PLCY_MST WHERE SALE_PLCY_CD = B.MODEL_SALE_POLICY_CODE) AS plcyNm /*판매정책명*/ , FN_GET_CODENM('CMN0058', (SELECT BL_DC_TYPE FROM MSP_JUO_ADD_INFO WHERE CONTRACT_NUM = A.CONTRACT_NUM AND BL_DC_TYPE IS NOT NULL AND ROWNUM = 1)) AS blDcType /*할인유형*/ , A.PROD_TYPE AS prodType , FN_GET_CODENM('RCP0063', NVL(A.PROD_TYPE, '01')) AS prodTypeNm , DECODE(A.CLAUSE_RENTAL_SERVICE, 'Y', 1, 0) AS clauseRentalService /*렌탈서비스 이용 동의*/ , DECODE(A.CLAUSE_RENTAL_MODEL_CP, 'Y', 1, 0) AS clauseRentalModelCp /*단말배상금 안내사항 동의*/ , DECODE(A.CLAUSE_RENTAL_MODEL_CP_PR, 'Y', 1, 0) AS clauseRentalModelCpPr /*단말배상금(부분파손) 안내사항 동의*/ , B.RENTAL_BASE_AMT AS rentalBaseAmt /*렌탈기본료*/ , B.RENTAL_BASE_DC_AMT AS rentalBaseDcAmt /*렌탈료할인*/ , B.RENTAL_MODEL_CP_AMT AS rentalModelCpAmt /*렌탈단말금액*/ FROM MSP_REQUEST A /* 가입신청정보 */ , MSP_REQUEST_SALEINFO B /* 판매정보 */ , MSP_REQUEST_CSTMR C /* 고객정보 */ , MSP_REQUEST_DLVRY D /* 배송정보 */ , MSP_REQUEST_STATE E /* 신청서상태정보 */ , MSP_REQUEST_REQ F /* 납부정보 */ , MSP_REQUEST_AGENT G /* 대리인정보 */ , MSP_REQUEST_MOVE H /* 번호이동정보 */ , MSP_REQUEST_PAYMENT I /* 선불충전 */ WHERE A.REQUEST_KEY = #{requestKey} AND A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND A.REQUEST_KEY = E.REQUEST_KEY(+) AND A.REQUEST_STATE_CODE = E.REQUEST_STATE_CODE(+) AND A.REQUEST_KEY = F.REQUEST_KEY AND A.REQUEST_KEY = G.REQUEST_KEY AND A.REQUEST_KEY = H.REQUEST_KEY AND A.REQUEST_KEY = I.REQUEST_KEY
